    51	    protected virtual IEnumerable<TypeParameterConstraintClauseSyntax> GetTypeParameterConstraintClauses()
    52	    {
    53	        foreach (var tp in Method.TypeParameters)
    54	        {
    55	            var constraints = new List<TypeParameterConstraintSyntax>();
    56	
    57	            if (tp.HasUnmanagedTypeConstraint)
    58	            {
    59	                constraints.Add(TypeConstraint(IdentifierName("unmanaged")).AddLeadingSpace());
    60	            }
    61	            else if (tp.HasValueTypeConstraint)
    62	            {
    63	                constraints.Add(ClassOrStructConstraint(SyntaxKind.StructConstraint).AddLeadingSpace());
    64	            }
    65	            else if (tp.HasNotNullConstraint)
    66	            {
    67	                constraints.Add(TypeConstraint(IdentifierName("notnull")).AddLeadingSpace());
    68	            }
    69	            else if (tp.HasReferenceTypeConstraint)
    70	            {
    71	                constraints.Add(ClassOrStructConstraint(SyntaxKind.ClassConstraint).AddLeadingSpace());
    72	            }
    73	
    74	            foreach (var c in tp.ConstraintTypes)
    75	            {
    76	                constraints.Add(TypeConstraint(FullyQualifiedIdentifier(c)).AddLeadingSpace());
    77	            }
    78	
    79	            if (tp.HasConstructorConstraint)
    80	            {
    81	                constraints.Add(ConstructorConstraint().AddLeadingSpace());
    82	            }
    83	
    84	            if (!constraints.Any())
    85	            {
    86	                continue;
    87	            }
    88	
    89	            yield return TypeParameterConstraintClause(
    90	                    IdentifierName(tp.Name).AddLeadingSpace().AddTrailingSpace(),
    91	                    SeparatedList(constraints)
