   127	    private IEnumerable<TypeParameterConstraintClauseSyntax> GetTypeParameterConstraintClauses()
   128	    {
   129	        foreach (var tp in Method.TypeParameters)
   130	        {
   131	            var constraints = new List<TypeParameterConstraintSyntax>();
   132	
   133	            if (tp.HasUnmanagedTypeConstraint)
   134	            {
   135	                constraints.Add(TypeConstraint(IdentifierName("unmanaged")).AddLeadingSpace());
   136	            }
   137	            else if (tp.HasValueTypeConstraint)
   138	            {
   139	                constraints.Add(ClassOrStructConstraint(SyntaxKind.StructConstraint).AddLeadingSpace());
   140	            }
   141	            else if (tp.HasNotNullConstraint)
   142	            {
   143	                constraints.Add(TypeConstraint(IdentifierName("notnull")).AddLeadingSpace());
   144	            }
   145	            else if (tp.HasReferenceTypeConstraint)
   146	            {
   147	                constraints.Add(ClassOrStructConstraint(SyntaxKind.ClassConstraint).AddLeadingSpace());
   148	            }
   149	
   150	            foreach (var c in tp.ConstraintTypes)
   151	            {
   152	                constraints.Add(TypeConstraint(FullyQualifiedIdentifier(c)).AddLeadingSpace());
   153	            }
   154	
   155	            if (tp.HasConstructorConstraint)
   156	            {
   157	                constraints.Add(ConstructorConstraint().AddLeadingSpace());
   158	            }
   159	
   160	            if (!constraints.Any())
   161	            {
   162	                continue;
   163	            }
   164	
   165	            yield return TypeParameterConstraintClause(
   166	                    IdentifierName(tp.Name).AddLeadingSpace().AddTrailingSpace(),
   167	                    SeparatedList(constraints)
   168	                )
   169	                .AddLeadingSpace();
   170	        }
   171	    }
