   173	    private SwitchSectionSyntax BuildSwitchSection(
   174	        TypeMappingBuildContext ctx,
   175	        IExistingTargetMapping mapping,
   176	        string sourceVariableName,
   177	        string targetVariableName
   178	    )
   179	    {
   180	        var sectionCtx = ctx.AddIndentation();
   181	
   182	        // (A source, B target)
   183	        var positionalTypeMatch = PositionalPatternClause(
   184	            CommaSeparatedList(
   185	                Subpattern(DeclarationPattern(mapping.SourceType, sourceVariableName)),
   186	                Subpattern(DeclarationPattern(mapping.TargetType, targetVariableName))
   187	            )
   188	        );
   189	        var pattern = RecursivePattern().WithPositionalPatternClause(positionalTypeMatch);
   190	
   191	        // case (A source, B target):
   192	        var caseLabel = CasePatternSwitchLabel(pattern).AddLeadingLineFeed(sectionCtx.SyntaxFactory.Indentation);
   193	
   194	        // break;
   195	        var statementContext = sectionCtx.AddIndentation();
   196	        var breakStatement = BreakStatement().AddLeadingLineFeed(statementContext.SyntaxFactory.Indentation);
   197	        var target = IdentifierName(targetVariableName);
   198	        var statements = mapping.Build(statementContext, target).Append(breakStatement);
   199	
   200	        return SwitchSection(caseLabel, statements);
   201	    }
