   203	    private SwitchSectionSyntax BuildDefaultSwitchSection(TypeMappingBuildContext ctx, ExpressionSyntax target)
   204	    {
   205	        // default:
   206	        var sectionCtx = ctx.SyntaxFactory.AddIndentation();
   207	        var defaultCaseLabel = DefaultSwitchLabel().AddLeadingLineFeed(sectionCtx.Indentation);
   208	
   209	        // throw new ArgumentException(msg, nameof(ctx.Source)),
   210	        var sourceTypeExpr = ctx.SyntaxFactory.Invocation(MemberAccess(ctx.Source, GetTypeMethodName));
   211	        var targetTypeExpr = ctx.SyntaxFactory.Invocation(MemberAccess(target, GetTypeMethodName));
   212	        var statementContext = sectionCtx.AddIndentation();
   213	        var throwExpression = ThrowArgumentExpression(
   214	                InterpolatedString($"Cannot map {sourceTypeExpr} to {targetTypeExpr} as there is no known type mapping"),
   215	                ctx.Source
   216	            )
   217	            .AddLeadingLineFeed(statementContext.Indentation);
   218	
   219	        var statements = new StatementSyntax[] { ExpressionStatement(throwExpression) };
   220	
   221	        return SwitchSection(defaultCaseLabel, statements);
   222	    }
