   224	    private StatementSyntax BuildNullGuard(TypeMappingBuildContext ctx)
   225	    {
   226	        var nullChecks = new List<ExpressionSyntax>();
   227	        if (SourceType.IsNullable() || CanBeNull(SourceType))
   228	        {
   229	            nullChecks.Add(IsNull(ctx.Source));
   230	        }
   231	
   232	        if (TargetType.IsNullable() || CanBeNull(TargetType))
   233	        {
   234	            nullChecks.Add(IsNull(IdentifierName(TargetParameter.Name)));
   235	        }
   236	
   237	        return ctx.SyntaxFactory.If(Or(nullChecks), ctx.SyntaxFactory.AddIndentation().Return());
