   219	    private INewInstanceMapping? InlineOrRebuild(UserImplementedMethodMapping mapping)
   220	    {
   221	        // Try inline first
   222	        // If the mapping is external, we don't report diagnostics yet,
   223	        // because we might be able to rebuild it if inlining fails.
   224	        var inlined = InlineExpressionMappingBuilder.TryBuildMapping(this, mapping);
   225	        if (inlined != null)
   226	            return inlined;
   227	
   228	        if (!mapping.IsExternal)
   229	        {
   230	            ReportDiagnostic(DiagnosticDescriptors.QueryableProjectionMappingCannotInline, mapping.Method);
   231	            return null;
   232	        }
   233	
   234	        // If not matched and is external, try rebuild
   235	        if (mapping.Method.IsPartialDefinition || AttributeAccessor.IsMapperlyGenerated(mapping.Method))
   236	        {
   237	            var ctx = ContextForMapping(
   238	                mapping,
   239	                new TypeMappingKey(mapping),
   240	                MappingBuildingOptions.Default,
   241	                mapping.Method.GetSyntaxLocation()
   242	            );
   243	
   244	            var rebuilt = MappingBuilder.Build(ctx, false);
   245	            if (rebuilt != null)
   246	                return rebuilt;
   247	        }
   248	
   249	        // If failed rebuild (or skipped), we need to report diagnostic that we couldn't inline.
   250	        // (Since we suppressed it in the first call).
   251	        ReportDiagnostic(DiagnosticDescriptors.QueryableProjectionMappingCannotInline, mapping.Method);
   252	        return null;
   253	    }
