using Riok.Mapperly.Descriptors.Mappings;
using Riok.Mapperly.Descriptors.Mappings.UserMappings;
using Riok.Mapperly.Helpers;

namespace Riok.Mapperly.Descriptors.MappingBuilders;

/// <summary>
/// Tries to match a type pair against user-implemented generic mapping methods.
/// If a matching method is found, creates a concrete mapping that calls the generic method
/// with resolved type arguments.
/// </summary>
public static class UserImplementedGenericMappingBuilder
{
    public static INewInstanceMapping? TryBuildMapping(MappingBuilderContext ctx)
    {
        // Don't try to use this for inline expression mappings
        if (ctx.IsExpression)
            return null;

        var genericMappings = ctx.MappingBuilder.GenericUserImplementedNewInstanceMappings;
        if (genericMappings.Count == 0)
            return null;

        foreach (var genericMapping in genericMappings)
        {
            // Try to infer type parameters by matching the source and target types
            var sourceType = ctx.Source;
            var targetType = ctx.Target;

            var result = ctx.GenericTypeChecker.InferAndCheckTypes(
                genericMapping.Method.TypeParameters,
                (genericMapping.SourceType, sourceType),
                (genericMapping.TargetType, targetType)
            );

            if (result.Success)
            {
                // Create a concrete delegate mapping that calls the generic method
                // with resolved type arguments
                var concreteMapping = new UserImplementedGenericDelegateMapping(
                    genericMapping,
                    sourceType,
                    targetType,
                    result.InferredTypes
                );

                return concreteMapping;
            }
        }

        return null;
    }
}

