using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp.Syntax;
using Riok.Mapperly.Helpers;
using static Microsoft.CodeAnalysis.CSharp.SyntaxFactory;
using static Riok.Mapperly.Emit.Syntax.SyntaxFactoryHelper;

namespace Riok.Mapperly.Descriptors.Mappings.UserMappings;

/// <summary>
/// A delegates to a user-implemented generic mapping method with resolved type arguments.
/// Generates: <c>MethodName&lt;ConcreteType1, ConcreteType2&gt;(source)</c>
/// </summary>
public class UserImplementedGenericDelegateMapping(
    UserImplementedNewInstanceGenericTypeMapping genericMapping,
    ITypeSymbol sourceType,
    ITypeSymbol targetType,
    IReadOnlyDictionary<ITypeParameterSymbol, ITypeSymbol> inferredTypes
) : NewInstanceMapping(sourceType, targetType)
{
    private readonly UserImplementedNewInstanceGenericTypeMapping _genericMapping = genericMapping;
    private readonly IReadOnlyDictionary<ITypeParameterSymbol, ITypeSymbol> _inferredTypes = inferredTypes;

    public override ExpressionSyntax Build(TypeMappingBuildContext ctx)
    {
        var method = _genericMapping.Method;

        // Build type arguments in the order of the method's type parameters
        var typeArgs = method.TypeParameters.Select(tp =>
            (TypeSyntax)IdentifierName(_inferredTypes[tp].FullyQualifiedIdentifierName())
        ).ToArray();

        var genericMethodName = GenericName(method.Name)
            .WithTypeArgumentList(TypeArgumentList(typeArgs));

        return ctx.SyntaxFactory.Invocation(genericMethodName, ctx.Source);
    }
}

