using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp.Syntax;
using Riok.Mapperly.Helpers;
using Riok.Mapperly.Symbols;
using static Riok.Mapperly.Emit.Syntax.SyntaxFactoryHelper;

namespace Riok.Mapperly.Descriptors.Mappings.UserMappings;

/// <summary>
/// Represents a user-implemented generic mapping method.
/// The user provides a fully implemented generic method which Mapperly calls
/// with the resolved type arguments for concrete type pairs.
/// </summary>
public class UserImplementedNewInstanceGenericTypeMapping(
    string? receiver,
    IMethodSymbol method,
    bool? isDefault,
    MethodParameter sourceParameter,
    ITypeSymbol targetType,
    MethodParameter? referenceHandlerParameter,
    bool isExternal
) : NewInstanceMapping(sourceParameter.Type, targetType), INewInstanceUserMapping
{
    public IMethodSymbol Method { get; } = method;

    public bool? Default { get; } = isDefault;

    public bool IsExternal { get; } = isExternal;

    public IReadOnlyCollection<MethodParameter> AdditionalSourceParameters => [];

    public override ExpressionSyntax Build(TypeMappingBuildContext ctx)
    {
        // Build a call to the generic method with resolved type arguments:
        // MethodName<ConcreteTargetType, ConcreteSourceType>(source)
        var typeArgs = Method.TypeParameters.Select(tp =>
        {
            // The type parameter is resolved by matching method parameter/return types
            // against the concrete SourceType/TargetType of this mapping instance.
            // Get the concrete type for each type parameter.
            var inferredTypes = ResolveTypeArguments();
            return (TypeSyntax)IdentifierName(inferredTypes[tp].FullyQualifiedIdentifierName());
        }).ToArray();

        var methodName = Method.Name;
        if (typeArgs.Length > 0)
        {
            var genericName = SyntaxFactory.GenericName(methodName)
                .WithTypeArgumentList(TypeArgumentList(typeArgs));
            return ctx.SyntaxFactory.Invocation(
                receiver == null ? genericName : SyntaxFactory.MemberAccessExpression(
                    Microsoft.CodeAnalysis.CSharp.SyntaxKind.SimpleMemberAccessExpression,
                    SyntaxFactory.IdentifierName(receiver),
                    genericName),
                ctx.Source
            );
        }

        return ctx.SyntaxFactory.Invocation(
            receiver == null ? SyntaxFactory.IdentifierName(methodName) : SyntaxFactory.MemberAccessExpression(
                Microsoft.CodeAnalysis.CSharp.SyntaxKind.SimpleMemberAccessExpression,
                SyntaxFactory.IdentifierName(receiver),
                SyntaxFactory.IdentifierName(methodName)),
            ctx.Source
        );
    }

    private IReadOnlyDictionary<ITypeParameterSymbol, ITypeSymbol> ResolveTypeArguments()
    {
        // Use a simple approach: map type parameters by position.
        // The method's SourceType and TargetType already have the concrete types,
        // so we can match them against the method's original parameter/return types.
        var result = new Dictionary<ITypeParameterSymbol, ITypeSymbol>(SymbolEqualityComparer.Default);

        // Match source parameter type
        ResolveTypeArgumentsRecursive(Method.Parameters[0].Type, SourceType, result);

        // Match return type
        ResolveTypeArgumentsRecursive(Method.ReturnType, TargetType, result);

        return result;
    }

    private static void ResolveTypeArgumentsRecursive(
        ITypeSymbol genericType,
        ITypeSymbol concreteType,
        Dictionary<ITypeParameterSymbol, ITypeSymbol> result)
    {
        if (genericType is ITypeParameterSymbol tp)
        {
            result[tp] = concreteType;
            return;
        }

        if (genericType is INamedTypeSymbol { IsGenericType: true } namedGeneric
            && concreteType is INamedTypeSymbol { IsGenericType: true } namedConcrete)
        {
            for (var i = 0; i < namedGeneric.TypeArguments.Length; i++)
            {
                ResolveTypeArgumentsRecursive(namedGeneric.TypeArguments[i], namedConcrete.TypeArguments[i], result);
            }
        }
    }
}

